from ag2 import GroupChat, GroupChatManager
from vex_sdk import VexHook

class RagQualityHook(VexHook):
    def __init__(self):
        self.relevance_threshold = 0.7

    def on_message(self, message, sender, recipients):
        if 'retrieval_scores' in message.content:
            scores = message.content['retrieval_scores']
            avg_score = sum(scores) / len(scores)
            if avg_score < self.relevance_threshold:
                self.flag_issue(
                    'LOW_RETRIEVAL_QUALITY',
                    f'Avg relevance {avg_score:.2f} < {self.relevance_threshold}',
                    message
                )

# Register with AG2 group chat
