manager = GroupChatManager(groupchat, hook=RagQualityHook())

def validate_citations(message):
    if 'citations' not in message.content:
        return True

    citations = message.content['citations']
    context = message.content.get('retrieved_context', [])

    for citation in citations:
        doc_id = citation['doc_id']
        claim = citation['claim']

        # Check if cited doc exists in context
        doc_exists = any(doc['id'] == doc_id for doc in context)
        if not doc_exists:
            return {'valid': False, 'issue': f'Missing doc {doc_id}'}

        # Check semantic similarity between claim and doc content
        doc_content = next(doc['content'] for doc in context if doc['id'] == doc_id)
        similarity = cosine_similarity([claim], [doc_content])[0][0]
        if similarity < 0.75:
            return {'valid': False, 'issue': f'Low similarity {similarity:.2f}'}

    return {'valid': True}

from collections import defaultdict

class ConsensusDriftDetector:
    def __init__(self):
        self.fact_votes = defaultdict(int)
        self.fact_sources = defaultdict(list)

    def process_message(self, message, sender):
        facts = self.extract_facts(message.content)
        for fact in facts:
            self.fact_votes[fact] += 1
            self.fact_sources[fact].append(sender.name)

            # Flag if 3+ agents agree on potentially wrong fact
            if self.fact_votes[fact] >= 3:
                if self.is_fact_suspicious(fact):
                    return {
                        'issue': 'CONSENSUS_DRIFT',
                        'fact': fact,
                        'supporters': self.fact_sources[fact],
                        'confidence': self.fact_votes[fact] / len(self.fact_sources[fact])
                    }
        return None

    def is_fact_suspicious(self, fact):
        # Check against known ground truth or external validator
        return 'deprecated' in fact.lower() or len(fact.split()) < 5

