from ag2 import GroupChatManager

class QualityWeightedGroupChatManager(GroupChatManager):
    def __init__(self, groupchat, quality_scores=None):
        super().__init__(groupchat)
        self.quality_scores = quality_scores or {agent.name: 1.0 for agent in groupchat.agents}

    def select_speaker(self, last_speaker, selector):
        # Weight speaker selection by recent retrieval quality
        candidates = [a for a in self.groupchat.agents if a != last_speaker]

        weighted_candidates = []
        for agent in candidates:
            quality = self.quality_scores.get(agent.name, 0.5)
            weight = quality * (1.0 + 0.1 * len(agent.recent_messages))  # Bonus for activity
            weighted_candidates.extend([agent] * int(weight * 10))

        if weighted_candidates:
            selected = selector.select_speaker(last_speaker, weighted_candidates)
            self.update_quality_score(selected, 0.9)  # Boost selected speaker
            return selected
        return super().select_speaker(last_speaker, selector)

    def update_quality_score(self, agent, score):
        self.quality_scores[agent.name] = 0.9 * self.quality_scores[agent.name] + 0.1 * score

class CascadeRagAgent:
    def __init__(self, retrievers):
        self.retrievers = retrievers  # List of (name, retriever, validator)

    def retrieve(self, query):
        for name, retriever, validator in self.retrievers:
            try:
                docs, scores = retriever.retrieve(query)
                if validator.validate(docs, scores):
                    return {'strategy': name, 'docs': docs, 'scores': scores}
            except Exception:
                continue

        # Final fallback: keyword search
        return self.retrievers[-1][1].retrieve(query)

